# ---- Routes ----

@app.route("/")
def index():
    if session.get("authenticated"):
        return redirect("/dashboard")
    return redirect("/login")


@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "GET":
        if session.get("authenticated"):
            return redirect("/dashboard")
        return render_template_string(LOGIN_PAGE, error=None, info=None)

    # POST: process login
    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")

    user = USERS.get(username)
    if not user:
        return render_template_string(LOGIN_PAGE, error="Invalid username or password.", info=None), 401

    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if not hmac.compare_digest(password_hash, user["password_hash"]):
        return render_template_string(LOGIN_PAGE, error="Invalid username or password.", info=None), 401

    # Password verified — set session
    session["authenticated"] = True
    session["username"] = username
    session["mfa_verified"] = False
    session["login_time"] = time.time()
    session["session_token"] = secrets.token_hex(16)

    if user.get("mfa_enabled") and user.get("mfa_secret"):
        # Mark MFA as pending
        PENDING_MFA[username] = {
            "session_token": session["session_token"],
            "timestamp": time.time(),
            "verified": False,
        }
        # Redirect to MFA verification
        return redirect("/verify-mfa")
    else:
        # No MFA enabled — fully authenticated
        session["mfa_verified"] = True
        return redirect("/dashboard")


@app.route("/verify-mfa", methods=["GET", "POST"])
@login_required
def verify_mfa():
    username = session.get("username")
    user = USERS.get(username)

    if not user or not user.get("mfa_enabled"):
        session["mfa_verified"] = True
        return redirect("/dashboard")

    if session.get("mfa_verified"):
        return render_template_string(MFA_PAGE,
                                      error=None,
                                      already_verified=True,
                                      current_code=None,
                                      mfa_secret=user["mfa_secret"])

    # Generate current TOTP for demo purposes
    current_code = generate_totp(user["mfa_secret"])

    if request.method == "GET":
        return render_template_string(MFA_PAGE,
                                      error=None,
                                      already_verified=False,
                                      current_code=current_code,
                                      mfa_secret=user["mfa_secret"])

    # POST: verify MFA code
    mfa_code = request.form.get("mfa_code", "").strip()

    if not mfa_code or len(mfa_code) != 6:
        return render_template_string(MFA_PAGE,
                                      error="Please enter a valid 6-digit code.",
                                      already_verified=False,
                                      current_code=current_code,
                                      mfa_secret=user["mfa_secret"]), 400

    if verify_totp(user["mfa_secret"], mfa_code):
        session["mfa_verified"] = True
        session["mfa_verified_time"] = time.time()

        # Update pending MFA record
        if username in PENDING_MFA:
            PENDING_MFA[username]["verified"] = True
            PENDING_MFA[username]["verified_time"] = time.time()

        return redirect("/dashboard")
    else:
        return render_template_string(MFA_PAGE,
                                      error="Invalid MFA code. Please try again.",
                                      already_verified=False,
                                      current_code=current_code,
                                      mfa_secret=user["mfa_secret"]), 401


@app.route("/verify-mfa-api", methods=["POST"])
@login_required
def verify_mfa_api():
    """API endpoint for background/AJAX MFA verification."""
    username = session.get("username")
    user = USERS.get(username)

    if not user or not user.get("mfa_enabled"):
        session["mfa_verified"] = True
        return jsonify({"status": "success", "message": "MFA not required"})

    if session.get("mfa_verified"):
        return jsonify({"status": "success", "message": "MFA already verified"})

    data = request.get_json() or {}
    mfa_code = data.get("mfa_code", "").strip()

    if not mfa_code or len(mfa_code) != 6:
        return jsonify({"status": "error", "message": "Invalid code format"}), 400

    if verify_totp(user["mfa_secret"], mfa_code):
        session["mfa_verified"] = True
        session["mfa_verified_time"] = time.time()

        if username in PENDING_MFA:
            PENDING_MFA[username]["verified"] = True
            PENDING_MFA[username]["verified_time"] = time.time()

        return jsonify({"status": "success", "message": "MFA verified successfully"})
    else:
        return jsonify({"status": "error", "message": "Invalid MFA code"}), 401


