@app.route("/logout")
def logout():
    username = session.get("username")
    if username and username in PENDING_MFA:
        del PENDING_MFA[username]
    session.clear()
    return redirect("/login")


@app.route("/register", methods=["GET", "POST"])
def register():
    """Simple user registration."""
    REGISTER_PAGE = """
    <!DOCTYPE html>
    <html>
    <head><title>Register</title>
    <style>
        body { font-family: Arial, sans-serif; max-width: 400px; margin: 50px auto; padding: 20px; }
        input, button { display: block; width: 100%%; padding: 10px; margin: 10px 0; box-sizing: border-box; }
        button { background: #28a745; color: white; border: none; cursor: pointer; border-radius: 4px; }
        button:hover { background: #218838; }
        .error { color: red; }
        .success { color: green; }
        h2 { text-align: center; }
    </style>
    </head>
    <body>
        <h2>Register</h2>
        {% if error %}<p class="error">{{ error }}</p>{% endif %}
        {% if success %}<p class="success">{{ success }} <a href="/login">Login now</a></p>{% endif %}
        <form method="POST" action="/register">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password (min 6 chars)" required>
            <input type="password" name="password_confirm" placeholder="Confirm Password" required>
            <button type="submit">Register</button>
        </form>
        <p style="text-align:center;"><a href="/login">Already have an account? Login</a></p>
    </body>
    </html>
    """

    if request.method == "GET":
        return render_template_string(REGISTER_PAGE, error=None, success=None)

    username = request.form.get("username", "").strip()
    password = request.form.get("password", "")
    password_confirm = request.form.get("password_confirm", "")

    if not username or not password:
        return render_template_string(REGISTER_PAGE, error="Username and password required.", success=None)

    if len(password) < 6:
        return render_template_string(REGISTER_PAGE, error="Password must be at least 6 characters.", success=None)

    if password != password_confirm:
        return render_template_string(REGISTER_PAGE, error="Passwords do not match.", success=None)

    if username in USERS:
        return render_template_string(REGISTER_PAGE, error="Username already exists.", success=None)

    USERS[username] = {
        "password_hash": hashlib.sha256(password.encode()).hexdigest(),
        "mfa_secret": base64.b32encode(os.urandom(20)).decode("utf-8"),
        "mfa_enabled": False,
    }

    return render_template_string(REGISTER_PAGE,
                                  error=None,
                                  success=f"Account '{username}' created! You can set up MFA after logging in.")


# ---- Error handlers ----

@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "Not found"}), 404


@app.errorhandler(500)
def server_error(e):
    return jsonify({"error": "Internal server error"}), 500


# ---- Cleanup old pending MFA entries ----

@app.before_request
def cleanup_pending_mfa():
    """Remove stale pending MFA entries older than 10 minutes."""
    cutoff = time.time() - 600
    stale_users = [u for u, data in PENDING_MFA.items() if data.get("timestamp", 0) < cutoff]
    for u in stale_users:
        del PENDING_MFA[u]


